from __future__ import annotations

from dataclasses import dataclass
from typing import ClassVar


class CronParseError(ValueError):
    """Raised when a cron expression is invalid."""


@dataclass(frozen=True)
class CronField:
    name: str
    expression: str
    minimum: int
    maximum: int
    values: tuple[int, ...]
    is_wildcard: bool = False

    def contains_all_values(self) -> bool:
        return len(self.values) == (self.maximum - self.minimum + 1)


@dataclass(frozen=True)
class CronSchedule:
    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    MONTH_NAMES: ClassVar[dict[int, str]] = {
        1: "January",
        2: "February",
        3: "March",
        4: "April",
        5: "May",
        6: "June",
        7: "July",
        8: "August",
        9: "September",
        10: "October",
        11: "November",
        12: "December",
    }

    DAY_NAMES: ClassVar[dict[int, str]] = {
        0: "Sunday",
        1: "Monday",
        2: "Tuesday",
        3: "Wednesday",
        4: "Thursday",
        5: "Friday",
        6: "Saturday",
    }

    def describe(self) -> str:
        if self._is_every_minute():
            return "Every minute"

        if self._is_simple_minute_step():
            step = self._step_from_expression(self.minute.expression)
            return f"Every {step} minutes"

        if self._is_simple_hour_step_on_the_hour():
            step = self._step_from_expression(self.hour.expression)
            return f"Every {step} hours, on the hour"

        parts = [self._describe_time()]

        date_parts = self._describe_date_parts()
        if date_parts:
            parts.append("on " + ", ".join(date_parts))

        return " ".join(parts)

    def _is_every_minute(self) -> bool:
        return all(
            field.is_wildcard
            for field in [
                self.minute,
                self.hour,
                self.day_of_month,
                self.month,
                self.day_of_week,
            ]
        )

    def _is_simple_minute_step(self) -> bool:
        return (
            self.minute.expression.startswith("*/")
            and self.hour.is_wildcard
            and self.day_of_month.is_wildcard
            and self.month.is_wildcard
            and self.day_of_week.is_wildcard
        )

    def _is_simple_hour_step_on_the_hour(self) -> bool:
        return (
            self.minute.values == (0,)
            and self.hour.expression.startswith("*/")
            and self.day_of_month.is_wildcard
            and self.month.is_wildcard
            and self.day_of_week.is_wildcard
        )

    def _describe_time(self) -> str:
        if self.minute.values == (0,) and self.hour.values == (0,):
            return "At midnight"

        if len(self.minute.values) == 1 and len(self.hour.values) == 1:
            hour = self.hour.values[0]
            minute = self.minute.values[0]
            return f"At {hour:02d}:{minute:02d}"

        if len(self.minute.values) == 1 and self.hour.is_wildcard:
            minute = self.minute.values[0]
            return f"At minute {minute} of every hour"

        return (
            f"At minutes {format_values(self.minute.values)} "
            f"of hours {format_values(self.hour.values)}"
        )

    def _describe_date_parts(self) -> list[str]:
        parts: list[str] = []

        if not self.day_of_month.is_wildcard:
            parts.append(self._describe_day_of_month())

        if not self.month.is_wildcard:
            parts.append(self._describe_month())

        if not self.day_of_week.is_wildcard:
            parts.append(self._describe_day_of_week())

        return parts

    def _describe_day_of_month(self) -> str:
        if self.day_of_month.values == (1,) and self.month.is_wildcard:
            return "the 1st of every month"

        days = [ordinal(value) for value in self.day_of_month.values]
        return format_words(days)

    def _describe_month(self) -> str:
        months = [self.MONTH_NAMES[value] for value in self.month.values]
        return "in " + format_words(months)

    def _describe_day_of_week(self) -> str:
        if self.day_of_week.expression == "1-5":
            return "Monday through Friday"

        days = [self.DAY_NAMES[value] for value in self.day_of_week.values]
        return format_words(days)

    @staticmethod
    def _step_from_expression(expression: str) -> int:
        return int(expression.split("/", maxsplit=1)[1])


FIELD_DEFINITIONS: tuple[tuple[str, int, int], ...] = (
    ("minute", 0, 59),
    ("hour", 0, 23),
    ("day_of_month", 1, 31),
    ("month", 1, 12),
    ("day_of_week", 0, 6),
)


def parse_cron(expression: str) -> CronSchedule:
    parts = expression.split()

    if len(parts) != 5:
        raise CronParseError(
            f"Expected 5 cron fields, got {len(parts)}: {expression!r}"
        )

    fields = [
        parse_field(raw_value, name, minimum, maximum)
        for raw_value, (name, minimum, maximum)
        in zip(parts, FIELD_DEFINITIONS)
    ]

    return CronSchedule(
        minute=fields[0],
        hour=fields[1],
        day_of_month=fields[2],
        month=fields[3],
        day_of_week=fields[4],
    )


def parse_field(
    expression: str,
    name: str,
    minimum: int,
    maximum: int,
) -> CronField:
    if not expression:
        raise CronParseError(f"{name} field cannot be empty")

    values: set[int] = set()

    for item in expression.split(","):
        values.update(parse_field_item(item, name, minimum, maximum))

    if not values:
        raise CronParseError(f"{name} field produced no values: {expression!r}")

    return CronField(
        name=name,
        expression=expression,
        minimum=minimum,
        maximum=maximum,
        values=tuple(sorted(values)),
        is_wildcard=expression == "*",
    )


def parse_field_item(
    item: str,
    name: str,
    minimum: int,
    maximum: int,
) -> set[int]:
    if not item:
        raise CronParseError(f"{name} field contains an empty list item")

    base, step = split_step(item, name)
    start, end = parse_range_base(base, name, minimum, maximum)

    if step is None:
        step = 1

    return set(range(start, end + 1, step))


def split_step(item: str, name: str) -> tuple[str, int | None]:
    if "/" not in item:
        return item, None

    parts = item.split("/")
    if len(parts) != 2:
        raise CronParseError(f"{name} field has invalid step syntax: {item!r}")

    base, step_text = parts

    if not step_text.isdigit():
        raise CronParseError(f"{name} field has non-numeric step: {item!r}")

    step = int(step_text)
    if step <= 0:
        raise CronParseError(f"{name} field step must be greater than zero: {item!r}")

    return base, step


def parse_range_base(
    base: str,
    name: str,
    minimum: int,
    maximum: int,
) -> tuple[int, int]:
    if base == "*":
        return minimum, maximum

    if "-" in base:
        return parse_range(base, name, minimum, maximum)

    value = parse_int(base, name)
    validate_value(value, name, minimum, maximum)
    return value, value


def parse_range(
    text: str,
    name: str,
    minimum: int,
    maximum: int,
) -> tuple[int, int]:
    parts = text.split("-")
    if len(parts) != 2:
        raise CronParseError(f"{name} field has invalid range: {text!r}")

    start = parse_int(parts[0], name)
    end = parse_int(parts[1], name)

    validate_value(start, name, minimum, maximum)
    validate_value(end, name, minimum, maximum)

    if start > end:
        raise CronParseError(
            f"{name} field range start must not exceed end: {text!r}"
        )

    return start, end


def parse_int(text: str, name: str) -> int:
    if not text.isdigit():
        raise CronParseError(f"{name} field contains a non-numeric value: {text!r}")

    return int(text)


def validate_value(
    value: int,
    name: str,
    minimum: int,
    maximum: int,
) -> None:
    if value < minimum or value > maximum:
        raise CronParseError(
            f"{name} field value {value} is outside allowed range "
            f"{minimum}-{maximum}"
        )


def ordinal(value: int) -> str:
    if 10 <= value % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(value % 10, "th")

    return f"{value}{suffix}"


def format_values(values: tuple[int, ...]) -> str:
    return format_words([str(value) for value in values])


def format_words(words: list[str]) -> str:
    if len(words) == 1:
        return words[0]

    if len(words) == 2:
        return f"{words[0]} and {words[1]}"

    return f"{', '.join(words[:-1])}, and {words[-1]}"


if __name__ == "__main__":
    examples = [
        "* * * * *",
        "0 12 * * 1-5",
        "*/15 * * * *",
        "0 0 1 * *",
        "30 8 * * 1,3,5",
        "0 */2 * * *",
    ]

    for cron_text in examples:
        schedule = parse_cron(cron_text)
        print(f"{cron_text!r} -> {schedule.describe()}")
